<script>
export default {
    props: {
        receipt_root: String,
    },
    methods: {
        async downloadXml() {
            const sampleXML = `<epos-print xmlns="http://www.epson-pos.com/schemas/2011/03/epos-print">
<text lang="ja"/>
<text font="font_a"/>
<page>
<area x="0" y="0" width="490" height="200"/>
<rectangle x1="31" y1="57" x2="489" y2="176" style="medium"/>
<position x="40" y="90"/>
<text dw="false" dh="false"/>
<text>{recog_time}</text>
<position x="300" y="90"/>
<text>{temperature}℃&#10;</text>
<position x="40" y="155"/>
<text dw="false" dh="true"/>
<text>【{person_code}】</text>
<text>{person_name}&#10;</text>
<text dw="false" dh="false"/>
<line x1="290" y1="60" x2="290" y2="99" style="medium"/>
<line x1="31" y1="100" x2="489" y2="100" style="medium"/>
<position x="220" y="230"/>
</page>
<cut type="feed"/>
</epos-print>`;

            // ダウンロード処理
            const blob = new Blob([sampleXML], { type: 'application/xml' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'sample.xml';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            window.URL.revokeObjectURL(url);

        }
    }
}
</script>

